s($,"aLz","an5",()=>A.pc("\ud83d\uded2 \u0637\u0644\u0628 \u0633\u0631\u064a\u0639 \u0648\u0633\u0647\u0644: \u062a\u0635\u0641\u0651\u062d \u0627\u0644\u0645\u0646\u062a\u062c\u0627\u062a \u0648\u0627\u0637\u0644\u0628\u0647\u0627 \u0628\u062e\u0637\u0648\u0627\u062a \u0628\u0633\u064a\u0637\u0629.\n\ud83d\ude9a \u062a\u0648\u0635\u064a\u0644 \u0645\u0648\u062b\u0648\u0642: \u064a\u062a\u0645 \u062a\u0646\u0641\u064a\u0630 \u0627\u0644\u0637\u0644\u0628\u0627\u062a \u0639\u0628\u0631 \u0645\u0646\u0627\u062f\u064a\u0628 \u0627\u0644\u0634\u0631\u0643\u0629 \u0627\u0644\u0645\u062f\u0631\u0628\u064a\u0646 \u0644\u0636\u0645\u0627\u0646 \u062f\u0642\u0629 \u0648\u0633\u0631\u0639\u0629 \u0627\u0644\u062a\u0648\u0635\u064a\u0644.\n\ud83d\udce6 \u062a\u062a\u0628\u0639 \u0627\u0644\u0637\u0644\u0628: \u062a\u0627\u0628\u0639 \u062d\u0627\u0644\u0629 \u0637\u0644\u0628\u0643 \u0644\u062d\u0638\u0629 \u0628\u0644\u062d\u0638\u0629 \u062d\u062a\u0649 \u0648\u0635\u0648\u0644\u0647 \u0625\u0644\u064a\u0643.\n\ud83d\udd14 \u0625\u0634\u0639\u0627\u0631\u0627\u062a \u0641\u0648\u0631\u064a\u0629: \u062a\u0635\u0644\u0643 \u062a\u0646\u0628\u064a\u0647\u0627\u062a \u0639\u0646 \u062d\u0627\u0644\u0629 \u0627\u0644\u0637\u0644\u0628 \u0648\u0627\u0644\u0639\u0631\u0648\u0636 \u0627\u0644\u062c\u062f\u064a\u062f\u0629.\n\ud83d\udc69\u200d\ud83d\udcbc \u062f\u0639\u0645 \u0641\u0646\u064a \u0645\u062a\u0648\u0627\u0635\u0644: \u062e\u062f\u0645\u0629 \u0639\u0645\u0644\u0627\u0621 \u062c\u0627\u0647\u0632\u0629 \u0644\u0644\u0631\u062f \u0639\u0644\u0649 \u0627\u0633\u062a\u0641\u0633\u0627\u0631\u0627\u062a\u0643 \u0639\u0644\u0649 \u0645\u062f\u0627\u0631 \u0627\u0644\u0633\u0627\u0639\u0629.\n","\ud83d\uded2 Quick and easy ordering: Browse products and order in a few simple steps.\n\ud83d\ude9a Reliable delivery: Orders are fulfilled by trained company representatives to ensure accurate and fast delivery.\n\ud83d\udce6 Order tracking: Follow the status of your order moment by moment until it arrives.\n\ud83d\udd14 Instant notifications: Receive alerts about order status and new offers.\n\ud83d\udc69\u200d\ud83d\udcbc Continuous technical support: Customer service is ready to answer your questions around the clock.\n"))
s($,"aLv","an3",()=>A.pc("\ud83e\udd6c \u0648\u0635\u0641 \u062a\u0637\u0628\u064a\u0642 \u0628\u0644\u0627\u0646\u062a\n\u062a\u0637\u0628\u064a\u0642 \u0628\u0644\u0627\u0646\u062a (Plant) \u0647\u0648 \u0645\u062a\u062c\u0631\u0643 \u0627\u0644\u0625\u0644\u0643\u062a\u0631\u0648\u0646\u064a \u0627\u0644\u0630\u0643\u064a \u0644\u0634\u0631\u0627\u0621 \u0627\u0644\u062e\u0636\u0627\u0631 \u0648\u0627\u0644\u0641\u0648\u0627\u0643\u0647 \u0627\u0644\u0637\u0627\u0632\u062c\u0629 \u0628\u0633\u0647\u0648\u0644\u0629 \u0648\u0633\u0631\u0639\u0629 \u0645\u0646 \u062c\u0648\u0627\u0644\u0643!\n\u064a\u0642\u062f\u0651\u0645 \u0644\u0643 \u062a\u062c\u0631\u0628\u0629 \u062a\u0633\u0648\u0651\u0642 \u0645\u0631\u064a\u062d\u0629 \u062a\u062a\u064a\u062d \u0627\u062e\u062a\u064a\u0627\u0631 \u0645\u0646\u062a\u062c\u0627\u062a\u0643 \u0627\u0644\u0645\u0641\u0636\u0644\u0629 \u0628\u062c\u0648\u062f\u0629 \u0639\u0627\u0644\u064a\u0629\u060c \u0644\u064a\u062a\u0645 \u062a\u062c\u0647\u064a\u0632\u0647\u0627 \u0648\u062a\u0648\u0635\u064a\u0644\u0647\u0627 \u0625\u0644\u0649 \u0628\u0627\u0628 \u0628\u064a\u062a\u0643 \u0641\u064a \u0627\u0644\u0648\u0642\u062a \u0627\u0644\u0630\u064a \u062a\u062e\u062a\u0627\u0631\u0647.\n\u2699\ufe0f \u0645\u0645\u064a\u0632\u0627\u062a \u0627\u0644\u062a\u0637\u0628\u064a\u0642:\n\ud83e\udd66 \u0645\u0646\u062a\u062c\u0627\u062a \u0637\u0627\u0632\u062c\u0629 \u064a\u0648\u0645\u064a\u064b\u0627: \u064a\u062a\u0645 \u0627\u062e\u062a\u064a\u0627\u0631 \u0627\u0644\u062e\u0636\u0627\u0631 \u0648\u0627\u0644\u0641\u0648\u0627\u0643\u0647 \u0628\u0639\u0646\u0627\u064a\u0629 \u0644\u0636\u0645\u0627\u0646 \u0623\u0639\u0644\u0649 \u062c\u0648\u062f\u0629.\n\ud83d\uded2 \u062a\u0633\u0648\u0651\u0642 \u0633\u0647\u0644 \u0648\u0633\u0631\u064a\u0639: \u0648\u0627\u062c\u0647\u0629 \u0628\u0633\u064a\u0637\u0629 \u062a\u0633\u0627\u0639\u062f\u0643 \u0639\u0644\u0649 \u0625\u062a\u0645\u0627\u0645 \u0627\u0644\u0637\u0644\u0628 \u062e\u0644\u0627\u0644 \u062b\u0648\u0627\u0646\u064d.\n\ud83d\ude9a \u062a\u0648\u0635\u064a\u0644 \u0633\u0631\u064a\u0639 \u0648\u0645\u0648\u062b\u0648\u0642: \u0646\u0648\u0635\u0644 \u0637\u0644\u0628\u0627\u062a\u0643 \u0641\u064a \u0623\u0633\u0631\u0639 \u0648\u0642\u062a \u0648\u0628\u0623\u0641\u0636\u0644 \u062a\u063a\u0644\u064a\u0641.\n\ud83d\udd14 \u0625\u0634\u0639\u0627\u0631\u0627\u062a \u0628\u0627\u0644\u0639\u0631\u0648\u0636: \u062a\u0627\u0628\u0639 \u0623\u062d\u062f\u062b \u0627\u0644\u062e\u0635\u0648\u0645\u0627\u062a \u0648\u0627\u0644\u0639\u0631\u0648\u0636 \u0627\u0644\u064a\u0648\u0645\u064a\u0629.\n\ud83c\udf3f \u062f\u0639\u0645 \u0639\u0645\u0644\u0627\u0621 \u0645\u0645\u064a\u0632: \u0641\u0631\u064a\u0642 \u062c\u0627\u0647\u0632 \u0644\u062e\u062f\u0645\u062a\u0643 \u0648\u0627\u0644\u0631\u062f \u0639\u0644\u0649 \u0627\u0633\u062a\u0641\u0633\u0627\u0631\u0627\u062a\u0643.\n","\ud83e\udd6c Plant App Description\nThe Plant app is your smart online store for buying fresh fruits and vegetables easily and quickly from your mobile phone!\nIt offers you a convenient shopping experience that allows you to choose your favorite high-quality products, which will be prepared and delivered to your doorstep at your chosen time.\n\u2699\ufe0f App Features:\n\ud83e\udd66 Fresh produce daily: Fruits and vegetables are carefully selected to ensure the highest quality.\n\ud83d\uded2 Easy and fast shopping: A simple interface helps you complete your order in seconds.\n\ud83d\ude9a Fast and reliable delivery: We deliver your orders as quickly as possible and with the best packaging.\n\ud83d\udd14 Special offers notifications: Stay up-to-date on the latest discounts and daily offers.\n\ud83c\udf3f Excellent customer support: A team ready to assist you and answer your questions.\n"))
s($,"aL8","amT",()=>A.pc("\ud83c\udfea \u0648\u0635\u0641 \u062a\u0637\u0628\u064a\u0642 \u0643\u0644\u064a\u0643\n\u062a\u0637\u0628\u064a\u0642 \u0643\u0644\u064a\u0643 (Click) \u0647\u0648 \u0627\u0644\u062d\u0644 \u0627\u0644\u0630\u0643\u064a \u0648\u0627\u0644\u0634\u0627\u0645\u0644 \u0644\u0625\u062f\u0627\u0631\u0629 \u0648\u062a\u0634\u063a\u064a\u0644 \u0645\u0643\u0627\u0626\u0646 \u0627\u0644\u0628\u064a\u0639 \u0627\u0644\u0630\u0627\u062a\u064a \u0628\u0643\u0644 \u0633\u0647\u0648\u0644\u0629 \u0648\u0627\u062d\u062a\u0631\u0627\u0641\u064a\u0629.\n\u064a\u0648\u0641\u0631 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0644\u0648\u062d\u0629 \u062a\u062d\u0643\u0645 \u0645\u062a\u0643\u0627\u0645\u0644\u0629 \u062a\u062a\u064a\u062d \u0644\u0644\u0645\u0634\u063a\u0644\u064a\u0646 \u0645\u062a\u0627\u0628\u0639\u0629 \u062d\u0627\u0644\u0629 \u0627\u0644\u0645\u0643\u0627\u0626\u0646\u060c \u0625\u062f\u0627\u0631\u0629 \u0627\u0644\u0645\u062e\u0632\u0648\u0646\u060c \u0645\u0631\u0627\u0642\u0628\u0629 \u0627\u0644\u0645\u0628\u064a\u0639\u0627\u062a \u0644\u062d\u0638\u064a\u064b\u0627\u060c \u0648\u062a\u062a\u0628\u0639 \u0639\u0645\u0644\u064a\u0627\u062a \u0627\u0644\u0635\u064a\u0627\u0646\u0629 \u0648\u0627\u0644\u062a\u0639\u0628\u0626\u0629\u060c \u0645\u0645\u0627 \u064a\u0636\u0645\u0646 \u0623\u062f\u0627\u0621\u064b \u0641\u0639\u0627\u0644\u064b\u0627 \u0648\u062a\u0642\u0644\u064a\u0644 \u0627\u0644\u0623\u0639\u0637\u0627\u0644 \u0648\u0627\u0644\u062e\u0633\u0627\u0626\u0631.\n\u2699\ufe0f \u0645\u0645\u064a\u0632\u0627\u062a \u0627\u0644\u062a\u0637\u0628\u064a\u0642:\n\n\ud83d\udcca \u0644\u0648\u062d\u0629 \u062a\u062d\u0643\u0645 \u0630\u0643\u064a\u0629: \u0639\u0631\u0636 \u0641\u0648\u0631\u064a \u0644\u0625\u062d\u0635\u0627\u0626\u064a\u0627\u062a \u0627\u0644\u0645\u0628\u064a\u0639\u0627\u062a \u0648\u062d\u0627\u0644\u0629 \u0643\u0644 \u0645\u0627\u0643\u064a\u0646\u0629.\n\ud83e\uddc3 \u0625\u062f\u0627\u0631\u0629 \u0627\u0644\u0645\u0646\u062a\u062c\u0627\u062a: \u062a\u0639\u062f\u064a\u0644 \u0627\u0644\u0623\u0633\u0639\u0627\u0631\u060c \u0625\u0636\u0627\u0641\u0629 \u0645\u0646\u062a\u062c\u0627\u062a \u062c\u062f\u064a\u062f\u0629\u060c \u0648\u0645\u062a\u0627\u0628\u0639\u0629 \u0627\u0644\u0643\u0645\u064a\u0627\u062a \u0627\u0644\u0645\u062a\u0648\u0641\u0631\u0629 \u062f\u0627\u062e\u0644 \u0627\u0644\u0645\u0627\u0643\u064a\u0646\u0627\u062a.\n\ud83d\udea8 \u062a\u0646\u0628\u064a\u0647\u0627\u062a \u0641\u0648\u0631\u064a\u0629: \u0625\u0634\u0639\u0627\u0631\u0627\u062a \u0639\u0646\u062f \u0627\u0646\u062e\u0641\u0627\u0636 \u0627\u0644\u0645\u062e\u0632\u0648\u0646 \u0623\u0648 \u062d\u062f\u0648\u062b \u0623\u0639\u0637\u0627\u0644.\n\ud83d\udcb0 \u062a\u0642\u0627\u0631\u064a\u0631 \u0645\u0627\u0644\u064a\u0629 \u062f\u0642\u064a\u0642\u0629: \u062a\u062d\u0644\u064a\u0644 \u0627\u0644\u0625\u064a\u0631\u0627\u062f\u0627\u062a \u0648\u0627\u0644\u0645\u0628\u064a\u0639\u0627\u062a \u0627\u0644\u064a\u0648\u0645\u064a\u0629 \u0623\u0648 \u0627\u0644\u0634\u0647\u0631\u064a\u0629.\n\ud83d\udc77 \u0625\u062f\u0627\u0631\u0629 \u0627\u0644\u0645\u0648\u0638\u0641\u064a\u0646 \u0648\u0627\u0644\u0645\u0634\u0631\u0641\u064a\u0646: \u062a\u062d\u062f\u064a\u062f \u0627\u0644\u0635\u0644\u0627\u062d\u064a\u0627\u062a \u0648\u0645\u062a\u0627\u0628\u0639\u0629 \u0623\u062f\u0627\u0621 \u0627\u0644\u0641\u0631\u064a\u0642.\n","\ud83c\udfea Click App Description\nThe Click app is the smart and comprehensive solution for managing and operating vending machines with ease and professionalism.\nThe app provides an integrated control panel that allows operators to monitor machine status, manage inventory, track sales in real time, and follow up on maintenance and replenishment processes, ensuring efficient performance and minimizing breakdowns and losses.\n\u2699\ufe0f App Features:\n\n\ud83d\udcca Smart Control Panel: Instant display of sales statistics and the status of each machine.\n\ud83e\uddc3 Product Management: Adjust prices, add new products, and track available quantities in the machines.\n\ud83d\udea8 Instant Alerts: Notifications when stock levels are low or malfunctions occur.\n\ud83d\udcb0 Accurate Financial Reports: Analysis of daily or monthly revenue and sales.\n\ud83d\udc77 Staff and Supervisor Management: Define permissions and monitor team performance.\n"))
s($,"aL2","Vw",()=>A.pc("\ud83d\udc68\u200d\ud83d\udcbc \u0648\u0635\u0641 \u062a\u0637\u0628\u064a\u0642 \u0627\u0644\u062d\u0636\u0648\u0631 \u0627\u0644\u0630\u0643\u064a \u0644\u0644\u0645\u0648\u0638\u0641\u064a\u0646\n\u062a\u0637\u0628\u064a\u0642 \u0627\u0644\u062d\u0636\u0648\u0631 \u0627\u0644\u0630\u0643\u064a \u0647\u0648 \u0646\u0638\u0627\u0645 \u0634\u0627\u0645\u0644 \u0644\u0625\u062f\u0627\u0631\u0629 \u062d\u0636\u0648\u0631 \u0648\u0627\u0646\u0635\u0631\u0627\u0641 \u0627\u0644\u0645\u0648\u0638\u0641\u064a\u0646 \u0628\u0637\u0631\u064a\u0642\u0629 \u0631\u0642\u0645\u064a\u0629 \u0633\u0647\u0644\u0629 \u0648\u0633\u0631\u064a\u0639\u0629.\n\u064a\u062a\u064a\u062d \u0644\u0644\u0645\u0648\u0638\u0641 \u062a\u0633\u062c\u064a\u0644 \u0627\u0644\u062f\u062e\u0648\u0644 \u0648\u0627\u0644\u062e\u0631\u0648\u062c \u064a\u0648\u0645\u064a\u064b\u0627\u060c \u0648\u0645\u0639\u0631\u0641\u0629 \u0645\u0648\u0627\u0639\u064a\u062f \u0639\u0645\u0644\u0647 \u0627\u0644\u0642\u0627\u062f\u0645\u0629\u060c \u0648\u0639\u062f\u062f \u0623\u064a\u0627\u0645 \u0627\u0644\u062d\u0636\u0648\u0631 \u0627\u0644\u0645\u0628\u0643\u0631 \u0648\u0627\u0644\u0627\u0646\u0635\u0631\u0627\u0641 \u0627\u0644\u0645\u0628\u0643\u0631\u060c \u0628\u0627\u0644\u0625\u0636\u0627\u0641\u0629 \u0625\u0644\u0649 \u062a\u062a\u0628\u0651\u0639 \u0627\u0644\u0625\u062c\u0627\u0632\u0627\u062a \u0648\u0627\u0644\u062a\u0623\u062e\u064a\u0631\u0627\u062a \u0628\u0643\u0644 \u062f\u0642\u0629 \u0648\u0648\u0636\u0648\u062d.\n\n\u2699\ufe0f \u0645\u0645\u064a\u0632\u0627\u062a \u0627\u0644\u062a\u0637\u0628\u064a\u0642:\n\ud83d\udd52 \u062a\u0633\u062c\u064a\u0644 \u0627\u0644\u062d\u0636\u0648\u0631 \u0648\u0627\u0644\u0627\u0646\u0635\u0631\u0627\u0641: \u0628\u0633\u0631\u0639\u0629 \u0639\u0628\u0631 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0623\u0648 \u0645\u0646 \u062e\u0644\u0627\u0644 \u062a\u062d\u062f\u064a\u062f \u0627\u0644\u0645\u0648\u0642\u0639.\n\ud83d\udcc5 \u0639\u0631\u0636 \u0627\u0644\u062c\u062f\u0627\u0648\u0644 \u0627\u0644\u0632\u0645\u0646\u064a\u0629: \u0645\u0639\u0631\u0641\u0629 \u0645\u0648\u0627\u0639\u064a\u062f \u0627\u0644\u0639\u0645\u0644 \u0627\u0644\u0642\u0627\u062f\u0645\u0629 \u0648\u0633\u0627\u0639\u0627\u062a \u0627\u0644\u062f\u0648\u0627\u0645 \u0627\u0644\u064a\u0648\u0645\u064a\u0629.\n\ud83d\udcc8 \u0625\u062d\u0635\u0627\u0626\u064a\u0627\u062a \u062f\u0642\u064a\u0642\u0629: \u0639\u062f\u062f \u0623\u064a\u0627\u0645 \u0627\u0644\u062d\u0636\u0648\u0631 \u0627\u0644\u0645\u0628\u0643\u0631\u060c \u0627\u0644\u0627\u0646\u0635\u0631\u0627\u0641 \u0627\u0644\u0645\u0628\u0643\u0631\u060c \u0627\u0644\u062a\u0623\u062e\u064a\u0631\u060c \u0648\u0627\u0644\u0625\u062c\u0627\u0632\u0627\u062a.\n\ud83e\ude7a \u0637\u0644\u0628\u0627\u062a \u0627\u0644\u0625\u062c\u0627\u0632\u0629: \u0625\u0645\u0643\u0627\u0646\u064a\u0629 \u062a\u0642\u062f\u064a\u0645 \u0637\u0644\u0628 \u0625\u062c\u0627\u0632\u0629 \u0645\u0631\u0636\u064a\u0629 \u0623\u0648 \u0637\u0627\u0631\u0626\u0629 \u0628\u0633\u0647\u0648\u0644\u0629.\n\u2705 \u0645\u062a\u0627\u0628\u0639\u0629 \u062d\u0627\u0644\u0629 \u0627\u0644\u0637\u0644\u0628: \u0645\u0639\u0631\u0641\u0629 \u0645\u0627 \u0625\u0630\u0627 \u062a\u0645 \u0642\u0628\u0648\u0644 \u0623\u0648 \u0631\u0641\u0636 \u0627\u0644\u0637\u0644\u0628 \u0645\u0628\u0627\u0634\u0631\u0629 \u0645\u0646 \u0627\u0644\u062a\u0637\u0628\u064a\u0642.\n\ud83d\udcac \u0645\u0631\u0627\u0633\u0644\u0629 \u0627\u0644\u062f\u0639\u0645: \u062a\u0648\u0627\u0635\u0644 \u0645\u0628\u0627\u0634\u0631 \u0645\u0639 \u0625\u062f\u0627\u0631\u0629 \u0627\u0644\u0645\u0648\u0627\u0631\u062f \u0627\u0644\u0628\u0634\u0631\u064a\u0629 \u0623\u0648 \u0627\u0644\u062f\u0639\u0645 \u0627\u0644\u0641\u0646\u064a \u0639\u0646\u062f \u0627\u0644\u062d\u0627\u062c\u0629.\n","\ud83d\udc68\u200d\ud83d\udcbc Smart Attendance App Description for Employees\nThe Smart Attendance App is a comprehensive system for managing employee attendance and departure in a quick and easy digital way.\nIt allows employees to log in and out daily, view their upcoming work schedules, track early arrival and early departure days, and accurately and clearly monitor vacations and lateness.\n\u2699\ufe0f App Features:\n\n\ud83d\udd52 Attendance and Departure Recording: Quickly log in and out via the app or by location.\n\ud83d\udcc5 Timetable Viewing: View upcoming work schedules and daily working hours.\n\ud83d\udcc8 Accurate Statistics: Number of early arrivals, early departures, lateness days, and vacations.\n\ud83e\ude7a Leave Requests: Easily submit sick leave or emergency leave requests. \u2705 Request Status Tracking: See whether the request has been approved or rejected directly from the app.\n\ud83d\udcac Support Contact: Directly contact Human Resources or Technical Support when needed.\n"))
s($,"aLr","an1",()=>A.pc("\ud83d\ude97 \u0648\u0635\u0641 \u062a\u0637\u0628\u064a\u0642 \u0645\u0633\u0627\u0631\u064a\n\u062a\u0637\u0628\u064a\u0642 \u0645\u0633\u0627\u0631\u064a \u0647\u0648 \u0645\u0646\u0635\u0651\u0629 \u0630\u0643\u064a\u0629 \u0648\u0633\u0647\u0644\u0629 \u0627\u0644\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0644\u062a\u0623\u062c\u064a\u0631 \u0627\u0644\u0633\u064a\u0627\u0631\u0627\u062a\u060c \u064a\u062a\u064a\u062d \u0644\u0643 \u0627\u0633\u062a\u0626\u062c\u0627\u0631 \u0627\u0644\u0633\u064a\u0627\u0631\u0629 \u0627\u0644\u0645\u0646\u0627\u0633\u0628\u0629 \u0644\u0643 \u062e\u0644\u0627\u0644 \u062f\u0642\u0627\u0626\u0642 \u0641\u0642\u0637\u060c \u0645\u0639 \u0625\u0645\u0643\u0627\u0646\u064a\u0629 \u0627\u0633\u062a\u0644\u0627\u0645\u0647\u0627 \u0645\u0628\u0627\u0634\u0631\u0629 \u0645\u0646 \u0645\u0648\u0642\u0639 \u0627\u0644\u062a\u0623\u062c\u064a\u0631 \u0628\u0643\u0644 \u0645\u0631\u0648\u0646\u0629 \u0648\u0633\u0647\u0648\u0644\u0629.\n\n\u2b50 \u0645\u0645\u064a\u0632\u0627\u062a \u0627\u0644\u062a\u0637\u0628\u064a\u0642:\n\ud83d\ude98 \u062a\u0623\u062c\u064a\u0631 \u0633\u064a\u0627\u0631\u0627\u062a \u0628\u0633\u0647\u0648\u0644\u0629 \u062a\u0627\u0645\u0629 \u0639\u0628\u0631 \u0648\u0627\u062c\u0647\u0629 \u0628\u0633\u064a\u0637\u0629 \u0648\u0633\u0631\u064a\u0639\u0629.\n\ud83d\udccd \u0627\u0633\u062a\u0644\u0627\u0645 \u0627\u0644\u0633\u064a\u0627\u0631\u0629 \u0645\u0646 \u0645\u0648\u0642\u0639 \u0627\u0644\u062a\u0623\u062c\u064a\u0631 \u062f\u0648\u0646 \u0623\u064a \u062a\u0639\u0642\u064a\u062f.\n\ud83d\udcc5 \u062d\u062c\u0632 \u0645\u0633\u0628\u0642 \u0648\u062a\u062d\u062f\u064a\u062f \u0645\u062f\u0629 \u0627\u0644\u0625\u064a\u062c\u0627\u0631 \u0627\u0644\u062a\u064a \u062a\u0646\u0627\u0633\u0628\u0643.\n\ud83d\udcb0 \u062e\u064a\u0627\u0631\u0627\u062a \u0645\u062a\u0646\u0648\u0639\u0629 \u0645\u0646 \u0627\u0644\u0633\u064a\u0627\u0631\u0627\u062a \u0628\u0623\u0633\u0639\u0627\u0631 \u062a\u0646\u0627\u0641\u0633\u064a\u0629.\n\ud83d\udd14 \u0625\u0634\u0639\u0627\u0631\u0627\u062a \u0628\u0627\u0644\u062d\u062c\u0648\u0632\u0627\u062a \u0648\u0627\u0644\u0639\u0631\u0648\u0636 \u0623\u0648\u0644\u0627\u064b \u0628\u0623\u0648\u0644.\n","\ud83d\ude97 Masari App Description\nThe Masari app is a smart and user-friendly car rental platform that allows you to rent the perfect car in just minutes, with the convenience of picking it up directly from the rental location.\n\n\u2b50 App Features:\n\n\ud83d\ude98 Rent a car with ease through a simple and fast interface.\n\ud83d\udccd Pick up your car from the rental location without any hassle.\n\ud83d\udcc5 Pre-book and choose the rental period that suits you.\n\ud83d\udcb0 A wide variety of cars at competitive prices.\n\ud83d\udd14 Get notified about bookings and special offers as soon as they become available.\n"))
s($,"aLg","amU",()=>A.pc("\ud83d\udee1\ufe0f \u0648\u0635\u0641 \u062a\u0637\u0628\u064a\u0642 Hr Shields\n\u062a\u0637\u0628\u064a\u0642 Hr Shields \u0647\u0648 \u0646\u0638\u0627\u0645 \u0630\u0643\u064a \u0648\u0645\u062a\u0643\u0627\u0645\u0644 \u0644\u0625\u062f\u0627\u0631\u0629 \u0634\u0624\u0648\u0646 \u0645\u0648\u0638\u0641\u064a \u0627\u0644\u0634\u0631\u0643\u0627\u062a \u0628\u0627\u062d\u062a\u0631\u0627\u0641\u064a\u0629 \u0648\u0633\u0647\u0648\u0644\u0629. \u064a\u0648\u0641\u0651\u0631 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u062d\u0644\u0648\u0644\u064b\u0627 \u0631\u0642\u0645\u064a\u0629 \u0645\u062a\u0642\u062f\u0645\u0629 \u0644\u062a\u0646\u0638\u064a\u0645 \u0627\u0644\u062d\u0636\u0648\u0631 \u0648\u0627\u0644\u0627\u0646\u0635\u0631\u0627\u0641\u060c \u0645\u062a\u0627\u0628\u0639\u0629 \u0627\u0644\u062c\u062f\u0627\u0648\u0644 \u0627\u0644\u0648\u0638\u064a\u0641\u064a\u0629\u060c \u0625\u062f\u0627\u0631\u0629 \u0627\u0644\u0625\u062c\u0627\u0632\u0627\u062a\u060c \u0648\u062a\u062d\u0633\u064a\u0646 \u0627\u0644\u062a\u0648\u0627\u0635\u0644 \u0628\u064a\u0646 \u0627\u0644\u0645\u0648\u0638\u0641\u064a\u0646 \u0648\u0625\u062f\u0627\u0631\u0629 \u0627\u0644\u0645\u0648\u0627\u0631\u062f \u0627\u0644\u0628\u0634\u0631\u064a\u0629.\n\n\u2b50 \u0645\u0645\u064a\u0632\u0627\u062a \u0627\u0644\u062a\u0637\u0628\u064a\u0642:\n\ud83d\udd52 \u062a\u0633\u062c\u064a\u0644 \u0627\u0644\u062d\u0636\u0648\u0631 \u0648\u0627\u0644\u0627\u0646\u0635\u0631\u0627\u0641 \u0628\u062f\u0642\u0629 \u0648\u0633\u0647\u0648\u0644\u0629.\n\ud83d\udcc5 \u0625\u062f\u0627\u0631\u0629 \u0645\u0648\u0627\u0639\u064a\u062f \u0627\u0644\u0639\u0645\u0644 \u0648\u0627\u0644\u062c\u062f\u0627\u0648\u0644 \u0627\u0644\u064a\u0648\u0645\u064a\u0629 \u0648\u0627\u0644\u0642\u0627\u062f\u0645\u0629.\n\ud83d\udcca \u062a\u0642\u0627\u0631\u064a\u0631 \u0648\u0625\u062d\u0635\u0627\u0626\u064a\u0627\u062a \u0630\u0643\u064a\u0629 \u0639\u0646 \u0627\u0644\u0627\u0644\u062a\u0632\u0627\u0645\u060c \u0627\u0644\u062a\u0623\u062e\u064a\u0631\u060c \u0648\u0627\u0644\u0627\u0646\u0635\u0631\u0627\u0641 \u0627\u0644\u0645\u0628\u0643\u0631.\n\ud83d\udcdd \u0625\u062f\u0627\u0631\u0629 \u0627\u0644\u0625\u062c\u0627\u0632\u0627\u062a (\u0633\u0646\u0648\u064a\u0629 \u2013 \u0645\u0631\u0636\u064a\u0629 \u2013 \u0637\u0627\u0631\u0626\u0629) \u0645\u0639 \u0645\u062a\u0627\u0628\u0639\u0629 \u062d\u0627\u0644\u0629 \u0627\u0644\u0637\u0644\u0628 (\u0645\u0642\u0628\u0648\u0644 / \u0645\u0631\u0641\u0648\u0636).\n\ud83d\udcac \u0645\u0631\u0627\u0633\u0644\u0629 \u0645\u0628\u0627\u0634\u0631\u0629 \u0628\u064a\u0646 \u0627\u0644\u0645\u0648\u0638\u0641\u064a\u0646 \u0648\u0642\u0633\u0645 \u0627\u0644\u0645\u0648\u0627\u0631\u062f \u0627\u0644\u0628\u0634\u0631\u064a\u0629.\n\ud83d\udd10 \u0635\u0644\u0627\u062d\u064a\u0627\u062a \u0645\u062a\u0639\u062f\u062f\u0629 \u062a\u0646\u0627\u0633\u0628 \u0645\u062e\u062a\u0644\u0641 \u0627\u0644\u0623\u062f\u0648\u0627\u0631 \u0627\u0644\u0648\u0638\u064a\u0641\u064a\u0629 \u062f\u0627\u062e\u0644 \u0627\u0644\u0634\u0631\u0643\u0629\n","\ud83d\udee1\ufe0f Hr Shields App Description\nThe Hr Shields app is a smart and integrated system for managing company employees professionally and easily. The app provides advanced digital solutions for organizing attendance and departure, tracking work schedules, managing leave, and improving communication between employees and HR.\n\n\u2b50 App Features:\n\ud83d\udd52 Accurate and easy attendance and departure recording.\n\ud83d\udcc5 Management of work schedules and daily and upcoming work plans.\n\ud83d\udcca Smart reports and statistics on punctuality, lateness, and early departure.\n\ud83d\udcdd Leave management (annual, sick, emergency) with request status tracking (approved/rejected).\n\ud83d\udcac Direct messaging between employees and the HR department.\n\ud83d\udd10 Multiple permissions to suit different job roles within the company.\n"))
s($,"aLy","an4",()=>A.pc("\ud83d\udee1\ufe0f \u0648\u0635\u0641 \u062a\u0637\u0628\u064a\u0642 \u0645\u0631\u0643\u0632 \u0627\u0644\u062a\u062d\u0641\u064a\u0638\n\n\ud83d\udcd6 \u0642\u0631\u0627\u0621\u0629 \u0627\u0644\u0642\u0631\u0622\u0646 \u0627\u0644\u0643\u0631\u064a\u0645 \u0628\u0633\u0647\u0648\u0644\u0629 \u0648\u0648\u0636\u0648\u062d\n\ud83c\udfa7 \u0627\u0644\u0627\u0633\u062a\u0645\u0627\u0639 \u0625\u0644\u0649 \u062a\u0644\u0627\u0648\u0627\u062a \u0639\u0630\u0628\u0629 \u0628\u0623\u0635\u0648\u0627\u062a \u0642\u0631\u0627\u0621 \u0645\u062e\u062a\u0644\u0641\u064a\u0646\n\ud83d\udcff \u0642\u0631\u0627\u0621\u0629 \u0627\u0644\u0623\u0630\u0643\u0627\u0631 \u0627\u0644\u064a\u0648\u0645\u064a\u0629 (\u0627\u0644\u0635\u0628\u0627\u062d\u060c \u0627\u0644\u0645\u0633\u0627\u0621\u060c \u0628\u0639\u062f \u0627\u0644\u0635\u0644\u0627\u0629\u060c \u0648\u063a\u064a\u0631\u0647\u0627)\n\ud83e\udde0 \u0645\u062a\u0627\u0628\u0639\u0629 \u0627\u0644\u062d\u0641\u0638 \u0648\u0627\u0644\u0645\u0631\u0627\u062c\u0639\u0629 \u0628\u0634\u0643\u0644 \u0645\u0646\u0638\u0645\n\ud83d\udc68\u200d\ud83c\udfeb \u0627\u0644\u062a\u0648\u0627\u0635\u0644 \u0645\u0639 \u0645\u062d\u0641\u0638\u064a\u0646 \u0645\u062a\u062e\u0635\u0635\u064a\u0646 \u0644\u0645\u0633\u0627\u0639\u062f\u062a\u0643 \u0641\u064a \u0627\u0644\u062d\u0641\u0638 \u0648\u0627\u0644\u062a\u062c\u0648\u064a\u062f\n\ud83c\udfc6 \u0627\u0644\u0645\u0634\u0627\u0631\u0643\u0629 \u0641\u064a \u062a\u062d\u062f\u064a\u0627\u062a \u0642\u0631\u0622\u0646\u064a\u0629 \u0644\u062a\u062d\u0641\u064a\u0632\u0643 \u0639\u0644\u0649 \u0627\u0644\u0627\u0633\u062a\u0645\u0631\u0627\u0631\n\ud83d\udcda \u062d\u0636\u0648\u0631 \u062f\u0631\u0648\u0633 \u062a\u0639\u0644\u064a\u0645\u064a\u0629 \u0644\u062a\u062d\u0633\u064a\u0646 \u0627\u0644\u062a\u0644\u0627\u0648\u0629 \u0648\u0641\u0647\u0645 \u0627\u0644\u0645\u0639\u0627\u0646\u064a\n","\ud83d\udee1\ufe0f Description of the Memorization Center App\n\n\ud83d\udcd6 Read the Holy Quran easily and clearly\n\ud83c\udfa7 Listen to beautiful recitations by various reciters\n\ud83d\udcff Read daily supplications (morning, evening, after prayer, etc.)\n\ud83e\udde0 Track your memorization and review in an organized manner\n\ud83d\udc68\u200d\ud83c\udfeb Connect with specialized teachers for assistance with memorization and Tajweed (rules of recitation)\n\ud83c\udfc6 Participate in Quranic challenges to motivate you to succeed\n\ud83d\udcda Attend classes to improve your recitation and understanding of the meanings\n"))
